SELECT

FROM resume_record
WHERE user_id = #{userId}

  AND tenant_id = #{tenantId}

ORDER BY uploaded_at DESC
LIMIT #{limit}

SELECT resume_id AS "resumeId", user_id AS "userId", original_name AS "originalName", size_bytes AS "sizeBytes", suffix, uploaded_at AS "uploadedAt", parse_status AS "parseStatus", parse_error AS "parseError", jsonb_strip_nulls(jsonb_build_object( 'folder', parsed_json::jsonb -> 'folder', 'resumeFolder', parsed_json::jsonb -> 'resumeFolder', 'version', parsed_json::jsonb -> 'version', 'resumeVersion', parsed_json::jsonb -> 'resumeVersion', 'labels', parsed_json::jsonb -> 'labels', 'manageTags', parsed_json::jsonb -> 'manageTags' ))::text AS "parsedJson" FROM resume_record WHERE user_id = #{userId}
AND tenant_id = #{tenantId}
AND LOWER(COALESCE(suffix, '')) = 'pdf' AND COALESCE(parsed_json::jsonb -> 'source' ->> 'type', '') NOT IN ('job_profile', 'boss_online_resume') ORDER BY uploaded_at DESC LIMIT #{limit}

SELECT COUNT(*)
FROM resume_record
WHERE resume_id = #{resumeId}

SELECT tenant_id
FROM app_user
WHERE user_id = #{userId}
